$work_program_seed$::jsonb) as record (
    id text,
    source text,
    reporter_name text,
    program_type text,
    block_field text,
    task_name text,
    scheduler_stage text,
    hectares numeric,
    actual_completion_date date,
    deadline date,
    priority text,
    approval_status text,
    remarks text,
    latitude numeric,
    longitude numeric,
    gps_accuracy text,
    photo_data text,
    sync_status text,
    category text,
    updated_at timestamptz
  )
)
insert into public.work_program_records (
  id,
  source,
  reporter_name,
  program_type,
  block_field,
  task_name,
  scheduler_stage,
  hectares,
  actual_completion_date,
  deadline,
  priority,
  approval_status,
  remarks,
  latitude,
  longitude,
  gps_accuracy,
  photo_data,
  sync_status,
  category,
  updated_at
)
select
  id,
  coalesce(nullif(source, ''), 'Excel Main actual'),
  reporter_name,
  program_type,
  block_field,
  coalesce(nullif(task_name, ''), 'Completion'),
  coalesce(nullif(scheduler_stage, ''), 'Completed'),
  hectares,
  actual_completion_date,
  deadline,
  priority,
  coalesce(nullif(approval_status, ''), 'Pending Approval'),
  remarks,
  latitude,
  longitude,
  gps_accuracy,
  photo_data,
  sync_status,
  category,
  coalesce(updated_at, now())
from seed_records
where id is not null
  and reporter_name is not null
  and program_type is not null
  and block_field is not null
  and hectares > 0
  and actual_completion_date is not null
  and approval_status in ('Pending Approval', 'Approved')
on conflict (id) do update set
  source = excluded.source,
  reporter_name = excluded.reporter_name,
  program_type = excluded.program_type,
  block_field = excluded.block_field,
  task_name = excluded.task_name,
  scheduler_stage = excluded.scheduler_stage,
  hectares = excluded.hectares,
  actual_completion_date = excluded.actual_completion_date,
  deadline = excluded.deadline,
  priority = excluded.priority,
  approval_status = excluded.approval_status,
  remarks = excluded.remarks,
  latitude = excluded.latitude,
  longitude = excluded.longitude,
  gps_accuracy = excluded.gps_accuracy,
  photo_data = excluded.photo_data,
  sync_status = excluded.sync_status,
  category = excluded.category;

select
  count(*) as work_program_seed_records
from public.work_program_records
where source = 'Excel Main actual';
